B.bX=new A.tf(3,"critica")
B.Du=new A.bA("clue_microscheda","La microscheda nel collare","Una piccola scheda di memoria, sporca di fango, agganciata al collare di uno dei gattini del rifugio. Contiene fotografie compromettenti.","Golasecca",B.bX,!1)
B.cb=new A.tf(2,"alta")
B.Dv=new A.bA("clue_bottone_strappato","Il bottone strappato","Nel fienile del maneggio, sotto una tavola smossa di recente, Segghy trova un bottone strappato durante una colluttazione.","Somma Lombardo",B.cb,!1)
B.Dw=new A.bA("clue_telefono_mauro","Il telefono rotto di Mauro","Recuperato dall'auto della vittima, portato in officina da Kledian per un finto controllo. Protetto da un codice di sblocco.","Vergiate",B.cb,!1)
B.Dx=new A.bA("clue_foto_tomba","Fotografie della tomba nascosta","Le foto nella microscheda ritraggono una tomba nascosta nel bosco, legata all'antica cultura di Golasecca.","Arsago Seprio",B.cb,!1)
B.dA=new A.tf(1,"media")
B.Dy=new A.bA("clue_macchia_scura","La macchia scura sul pavimento","Una macchia scura sul pavimento del fienile, nello stesso angolo verso cui Nebbia continua a tirare quando sente il campanello.","Somma Lombardo",B.dA,!1)
B.Dz=new A.bA("clue_telecamera_spenta","La telecamera spenta","Moreno ammette di aver spento una delle telecamere della zona fluviale quella notte, dietro minaccia di Mauro.","Castelletto sopra Ticino",B.cb,!1)
B.DA=new A.bA("clue_fango_zampe","Fango sulle zampe","Il fango sulle zampe del gattino \xe8 identico a quello della riva del Ticino vicino al maneggio, non a quello della villa.","Golasecca",B.dA,!1)
B.DB=new A.bA("clue_impronte_doppie","Impronte doppie nel fango","Lungo la riva del Ticino, delle impronte doppie e profonde suggeriscono che qualcuno abbia trascinato un peso verso l'acqua.","Sesto Calende",B.cb,!1)
B.DC=new A.bA("clue_registro_visite","Il registro delle visite notturne","Ricostruendo con cura gli orari di quella notte, risulta che qualcuno ha lasciato il maneggio molto dopo l'ora dichiarata ufficialmente.","Somma Lombardo",B.bX,!1)
B.DD=new A.bA("clue_contratto_adriano","Il contratto capestro","Il contratto con cui Mauro si \xe8 impossessato delle quote societarie di Adriano, firmato subito dopo la morte del padre di lui, in un momento di fragilit\xe0.","Sesto Calende",B.cb,!1)
B.DE=new A.bA("clue_biglietto_bagnato","Il biglietto bagnato",'Un biglietto quasi illeggibile, recuperato tra i canneti: si legge solo "...al maneggio, dopo mezzanotte...".',"Sesto Calende",B.cb,!1)
B.DF=new A.bA("clue_impronta_estranea","L'impronta estranea","Tra le impronte rilevate sullo scafo della barca, una \xe8 pi\xf9 piccola delle altre e non corrisponde a nessun ospite noto della festa: qualcuno di corporatura minuta \xe8 salito a bordo quella notte.","Sesto Calende",B.bX,!1)
B.DG=new A.bA("clue_gattino_infreddolito","Il gattino trovato vicino alla villa","Uno dei gattini del rifugio \xe8 stato trovato la notte dell'omicidio a poca distanza dalla villa, infreddolito e spaventato.","Golasecca",B.dA,!1)
B.n7=new A.tf(0,"bassa")
B.DH=new A.bA("clue_leggenda_fibula","La leggenda della fibula","Una leggenda locale narra di una fibula in bronzo che protegge chi la possiede, ma porta rovina a chi la ruba: l'oggetto che Mauro cercava.","Arsago Seprio",B.n7,!1)
B.DI=new A.bA("clue_alibi_adriano","Il buco nell'alibi di Adriano","Adriano sostiene di essere stato altrove quella notte, ma il suo racconto lascia scoperta quasi un'ora, proprio a cavallo dell'omicidio.","Sesto Calende",B.dA,!1)
B.DJ=new A.bA("clue_ciondolo_falso","Il ciondolo piazzato","Il ciondolo a forma di cavallo ritrovato accanto al corpo di Mauro \xe8 identico a quello di Segghy, ma lei lo ha perso durante la festa: qualcuno lo ha raccolto e messo l\xec apposta.","Golasecca",B.bX,!1)
B.DK=new A.bA("clue_campanello","Il campanello da bicicletta","Un vecchio campanello da bicicletta, dello stesso modello di quello che Sandra tiene agganciata alla sua bici. Nebbia si agita ogni volta che lo sente.","Somma Lombardo",B.bX,!1)
B.DL=new A.bA("clue_frase_sandra","La frase di troppo di Sandra","Al bar, Sandra lascia scappare un dettaglio sulla posizione esatta del corpo di Mauro: un particolare mai reso pubblico.","Golasecca",B.bX,!1)
B.DM=new A.bA("clue_mappa_alterata","La mappa archeologica alterata","Le coordinate sulla mappa usata da Mauro per orientare gli scavi abusivi sono state falsificate da Alessandra per proteggere il sito reale.","Arsago Seprio",B.bX,!1)
B.DN=new A.bA("clue_promessa_manuela","La promessa di Manuela a Cinzia","Manuela aveva promesso a Cinzia, un giorno, di aiutarla a riprendersi il maneggio: un legame antico che nessuna delle due ha mai raccontato del tutto.","Somma Lombardo",B.dA,!1)
B.DO=new A.bA("clue_prestito_cinzia","Il prestito capestro di Cinzia","I documenti del prestito concesso da Mauro a Cinzia anni prima, con clausole scritte apposta per farla fallire e prendersi il maneggio.","Somma Lombardo",B.cb,!1)
B.DP=new A.bA("clue_orario_festa","L'orario esatto della festa","Confrontando gli inviti e i racconti degli ospiti, Segghy ricostruisce una finestra oraria precisa in cui Mauro \xe8 stato visto vivo l'ultima volta.","Golasecca",B.n7,!1)
B.DQ=new A.bA("clue_video_incappucciato","Il video della figura incappucciata","Una telecamera privata riprende, la notte dell'omicidio, una figura incappucciata che getta qualcosa nel fiume, sulla riva opposta.","Castelletto sopra Ticino",B.bX,!1)
B.DR=new A.bA("clue_documenti_maneggio","I documenti del ricatto","I documenti che Manuela cercava disperatamente di recuperare da Mauro la notte dell'omicidio, prova del vecchio debito.","Somma Lombardo",B.bX,!1)
B.DS=new A.bA("clue_messaggi_cancellati","Messaggi cancellati","Una cronologia di chiamate e messaggi cancellati, recuperata dal telefono di Mauro: prova che ricattava pi\xf9 persone contemporaneamente.","Vergiate",B.cb,!1)
B.DT=new A.bA("clue_confessione","La confessione di Sandra","Messa di fronte a tutte le prove raccolte, Sandra confessa: aveva scoperto che Mauro era responsabile della morte di suo fratello sul Ticino.","Golasecca",B.bX,!1)
B.DU=new A.bA("clue_vaso_rovesciato","Il vaso rovesciato","Nella serra della villa, un vaso rovesciato suggerisce una colluttazione avvenuta poco prima della morte di Mauro.","Golasecca",B.dA,!1)
B.DV=new A.a1n(1,"matrix")
